  1	import * as React from 'react';
  2	import { Card, CardBody, CardHeader, Title, TitleSizes, Tooltip, TooltipPosition } from '@patternfly/react-core';
  3	import { ServiceDetailsInfo } from '../../types/ServiceInfo';
  4	import { kialiStyle } from 'styles/StyleUtils';
  5	import { Gateway, ObjectCheck, ObjectValidation, VirtualService } from '../../types/IstioObjects';
  6	import { ValidationList } from '../../components/Validations/ValidationList';
  7	import { KialiIcon } from '../../config/KialiIcon';
  8	import { infoStyle } from 'styles/IconStyle';
  9	
 10	type ServiceNetworkProps = {
 11	  gateways: Gateway[];
 12	  serviceDetails: ServiceDetailsInfo;
 13	  validations?: ObjectValidation;
 14	};
 15	
 16	type HostnameInfo = {
 17	  fromName: string | undefined;
 18	  fromType: string | undefined;
 19	  hostname: string;
 20	};
 21	
 22	const resourceListStyle = kialiStyle({
 23	  $nest: {
 24	    '& > ul > li > span': {
 25	      float: 'left',
 26	      width: '125px',
 27	      fontWeight: 700
 28	    }
 29	  }
 30	});
 31	
 32	export const ServiceNetwork: React.FC<ServiceNetworkProps> = (props: ServiceNetworkProps) => {
 33	  const getPortOver = (portId: number): React.ReactNode => {
 34	    return <ValidationList checks={getPortChecks(portId)} />;
 35	  };
 36	
 37	  const getPortChecks = (portId: number): ObjectCheck[] => {
 38	    return props.validations ? props.validations.checks.filter(c => c.path === `spec/ports[${portId}]`) : [];
 39	  };
 40	
 41	  const hasIssue = (portId: number): boolean => {
 42	    return getPortChecks(portId).length > 0;
 43	  };
 44	
 45	  const getHostnames = (virtualServices: VirtualService[]): HostnameInfo[] => {
 46	    let hostnames: HostnameInfo[] = [];
 47	
 48	    virtualServices.forEach(vs => {
 49	      vs.spec.hosts?.forEach(host => {
 50	        if (host === '*') {
 51	          vs.spec.gateways?.forEach(vsGatewayName => {
 52	            const vsGateways = props.gateways.filter(gateway => {
 53	              return gateway.metadata.name === vsGatewayName;
 54	            });
 55	
 56	            vsGateways.forEach(vsGateway => {
 57	              vsGateway.spec.servers?.forEach(servers => {
 58	                servers.hosts.forEach(host => {
 59	                  hostnames.push({ hostname: host, fromType: vsGateway.kind, fromName: vsGateway.metadata.name });
 60	                });
 61	              });
 62	            });
 63	          });
 64	        } else {
 65	          hostnames.push({ hostname: host, fromType: vs.kind, fromName: vs.metadata.name });
 66	        }
 67	      });
 68	    });
 69	
 70	    // If there is a wildcard, then it will display only one, the first match
 71	    for (let hostnameInfo of hostnames) {
 72	      if (hostnameInfo.hostname === '*') {
 73	        return [hostnameInfo];
 74	      }
 75	    }
 76	
 77	    return hostnames;
 78	  };
 79	
 80	  const service = props.serviceDetails.service;
 81	  let ips = service.type !== 'External' ? (service.ips ? service.ips : [service.ip]) : [];
 82	  return (
 83	    <Card isCompact={true} id="ServiceNetworkCard">
 84	      <CardHeader>
 85	        <Title headingLevel="h3" size={TitleSizes['xl']}>
 86	          Network
 87	        </Title>
 88	      </CardHeader>
 89	      <CardBody>
 90	        <div key="network-list" className={resourceListStyle}>
 91	          <ul style={{ listStyleType: 'none' }}>
 92	            <li>
 93	              <span>Type</span>
 94	              {service.type}
 95	            </li>
 96	
 97	            {ips.map((ip, i) => (
 98	              <li>
 99	                <span>
100	                  {service.type !== 'ExternalName'
101	                    ? `Service ${service.ipFamilies ? service.ipFamilies[i] : 'IP'}`
102	                    : 'ExternalName'}
103	                </span>
104	                {service.type !== 'ExternalName' ? ip : service.externalName ? service.externalName : ''}
105	              </li>
106	            ))}
107	
108	            {props.serviceDetails.endpoints && props.serviceDetails.endpoints.length > 0 && (
109	              <li>
110	                <span>Endpoints</span>
111	                <div style={{ display: 'inline-block' }}>
112	                  {(props.serviceDetails.endpoints ?? []).map((endpoint, i) => {
113	                    return (endpoint.addresses ?? []).map((address, u) => (
114	                      <div key={`endpoint_${i}_address_${u}`}>
115	                        {address.name !== '' ? (
116	                          <Tooltip
117	                            position={TooltipPosition.right}
118	                            content={
119	                              <div style={{ textAlign: 'left' }}>
120	                                {address.kind}: {address.name}
121	                              </div>
122	                            }
123	                          >
124	                            <span>
125	                              {address.ip} <KialiIcon.Info className={infoStyle} />
126	                            </span>
127	                          </Tooltip>
128	                        ) : (
129	                          <>{address.name}</>
130	                        )}
131	                      </div>
132	                    ));
133	                  })}
134	                </div>
135	              </li>
136	            )}
137	
138	            {service.ports && service.ports.length > 0 && (
139	              <li>
140	                <span>Ports</span>
141	                <div style={{ display: 'inline-block' }}>
142	                  {(service.ports ?? []).map((port, i) => {
143	                    return (
144	                      <div key={`port_${i}`}>
145	                        <div>
146	                          <span style={{ marginRight: '0.5rem' }}>
147	                            {port.name} {port.port}
148	                          </span>
149	                          {hasIssue(i) ? getPortOver(i) : undefined}
150	                          {port.appProtocol && port.appProtocol !== '' ? (
151	                            <Tooltip
152	                              position={TooltipPosition.right}
153	                              content={<div style={{ textAlign: 'left' }}>App Protocol: {port.appProtocol}</div>}
154	                            >
155	                              <span style={{ marginRight: '0.25rem' }}>
156	                                <KialiIcon.Info className={infoStyle} />
157	                              </span>
158	                            </Tooltip>
159	                          ) : undefined}
160	                        </div>
161	                        <div>({port.protocol})</div>
162	                      </div>
163	                    );
164	                  })}
165	                </div>
166	              </li>
167	            )}
168	
169	            {props.serviceDetails.virtualServices.length > 0 && (
170	              <li>
171	                <span>Hostnames</span>
172	                <div style={{ display: 'inline-block' }}>
173	                  {getHostnames(props.serviceDetails.virtualServices).map((hostname, i) => {
174	                    return (
175	                      <div key={`hostname_${i}`} style={{ width: 'fit-content' }}>
176	                        <Tooltip
177	                          position={TooltipPosition.right}
178	                          content={
179	                            <div style={{ textAlign: 'left' }}>
180	                              {hostname.fromType} {hostname.fromName}: {hostname.hostname}
181	                            </div>
182	                          }
183	                        >
184	                          <div style={{ display: 'flex' }}>
185	                            <span
186	                              style={{
187	                                whiteSpace: 'nowrap',
188	                                overflow: 'hidden',
189	                                textOverflow: 'ellipsis'
190	                              }}
191	                            >
192	                              {hostname.hostname}
193	                            </span>
194	                            <span>
195	                              <KialiIcon.Info className={infoStyle} />
196	                            </span>
197	                          </div>
198	                        </Tooltip>
199	                      </div>
200	                    );
201	                  })}
202	                </div>
203	              </li>
204	            )}
205	          </ul>
206	        </div>
207	      </CardBody>
208	    </Card>
209	  );
210	};

